import{_ as t,o as a,c as o,ag as i}from"./chunks/framework.fgRodP1M.js";const m=JSON.parse('{"title":"2026-W18 Tech Log","description":"","frontmatter":{},"headers":[],"relativePath":"tech-log/2026/2026-w18.md","filePath":"tech-log/2026/2026-w18.md","lastUpdated":1777962526000}'),r={name:"tech-log/2026/2026-w18.md"};function n(s,e,l,c,d,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="_2026-w18-tech-log" tabindex="-1">2026-W18 Tech Log <a class="header-anchor" href="#_2026-w18-tech-log" aria-label="Permalink to &quot;2026-W18 Tech Log&quot;">​</a></h1><p>Week of <strong>2026-05-04</strong> — integration-heavy week on a manipulation stack (ROS 2 Humble, custom hardware interface).</p><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Brought a <strong>velocity-saturated torque controller</strong> online in simulation, then chased real-robot discrepancies caused by timing jitter and an underestimated friction model. Ended the week with repeatable pick trials on three representative objects.</p><h2 id="what-i-worked-on" tabindex="-1">What I Worked On <a class="header-anchor" href="#what-i-worked-on" aria-label="Permalink to &quot;What I Worked On&quot;">​</a></h2><ul><li>Wrapped an existing inverse dynamics block so it could run at a fixed <strong>500 Hz</strong> control loop with explicit deadline monitoring.</li><li>Instrumented the hardware bridge: message age histograms for <code>sensor_msgs/JointState</code> and command topics.</li><li>Tuned a simple <strong>Coulomb + viscous</strong> friction estimator from logged free-motion coast-down data.</li><li>Paired with perception to align grasp frame conventions between offline planning and online servoing.</li></ul><h2 id="problems-i-solved" tabindex="-1">Problems I Solved <a class="header-anchor" href="#problems-i-solved" aria-label="Permalink to &quot;Problems I Solved&quot;">​</a></h2><ul><li><strong>Executor starvation</strong>: a diagnostic node accidentally lived in the same callback group as the controller; splitting groups restored predictable scheduling.</li><li><strong>Sign convention drift</strong> between URDF inertia frames and the vendor driver: added a one-time self-test that commands micro-motions and checks predicted vs measured acceleration direction.</li><li>Pick failures on a glossy box traced to <strong>latency</strong> in the depth pipeline, not the grasp planner; shifted to a conservative pre-grasp hover with shorter visual servo distance.</li></ul><h2 id="what-i-learned" tabindex="-1">What I Learned <a class="header-anchor" href="#what-i-learned" aria-label="Permalink to &quot;What I Learned&quot;">​</a></h2><ul><li>Histograms of message age beat averages for spotting “mostly fine, sometimes awful” DDS behavior.</li><li>When friction is wrong, <strong>integral windup</strong> in outer loops looks like “mysterious instability at contact,” not a classic tuning problem.</li></ul><h2 id="technical-notes" tabindex="-1">Technical Notes <a class="header-anchor" href="#technical-notes" aria-label="Permalink to &quot;Technical Notes&quot;">​</a></h2><ul><li>Outer loop: Cartesian impedance with a wrench cap; inner loop: PD on joint torque with saturation aware of motor thermal limits (conservative caps during bring-up).</li><li>Logged fields included commanded torque, measured torque (where available), tracking error, and executor overrun flags for post hoc alignment with video.</li></ul><h2 id="public-insight" tabindex="-1">Public Insight <a class="header-anchor" href="#public-insight" aria-label="Permalink to &quot;Public Insight&quot;">​</a></h2><p>Reliable manipulation is less about a clever grasp metric and more about <strong>time determinism</strong> from camera to actuator. If your perception stack is honest about latency, the rest of the stack can be honest too.</p><h2 id="next-actions" tabindex="-1">Next Actions <a class="header-anchor" href="#next-actions" aria-label="Permalink to &quot;Next Actions&quot;">​</a></h2><ul><li>Automate coast-down captures across the workspace so friction estimates are not single-pose artifacts.</li><li>Draft a short article on <strong>callback group layout</strong> for control-critical ROS 2 nodes (target: <a href="/lifeops_blog/articles/ros2/">ROS 2</a> category).</li><li>Add a regression bag for the three pick objects so CI can replay timing-sensitive paths in simulation.</li></ul>',16)])])}const g=t(r,[["render",n]]);export{m as __pageData,g as default};
